INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00257', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '為提升受刑人謀生技能，有助於復歸社會，受刑人在監一律強制參加作業但也有例外情形，就此例外 情形，下列敘述何者錯誤？', '["受刑人罹患疾病，得不參加作業", "受刑人受和緩處遇原因消滅，得不參加作業", "受刑人於入監調查期間，得不參加作業", "受刑人有妨害戒護安全之情形，得不參加作業"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00258', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依行刑累進處遇條例之規定，各級受刑人得准其於每月所得作業勞作金中，可自由使用之範圍，下列 敘述何者錯誤？', '["第四級受刑人於五分之一範圍內，自由使用", "第三級受刑人於四分之一範圍內，自由使用", "第二級受刑人於三分之一範圍內，自由使用", "第一級受刑人，自由使用範圍，沒有特別限制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00259', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["監獄人員執行職務應尊重受刑人之尊嚴及維護其人權，不得逾越所欲達成矯治處遇目的之必要限度", "監獄得對受刑人施以逾十五日之單獨監禁", "監獄應以積極適當之方式及措施，使受刑人瞭解其所受處遇及刑罰執行之目的", "監獄應保障身心障礙受刑人在監獄內之無障礙權益，並採取適當措施為合理調整"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00260', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["為落實透明化原則，保障受刑人權益，監獄應設獨立之外部視察小組，置委員三人至七人，任期二 年，均為有給職，由監督機關陳報法務部核定後遴聘之", "監獄應設之獨立外部視察小組的委員，應就法律、醫學、公共衛生、心理、犯罪防治或人權領域之 專家學者遴選之。其中任一性別委員比例不予限制", "監獄應設之獨立外部視察小組應就監獄運作及受刑人權益等相關事項，進行視察並每月提出報告， 由監獄經監督機關陳報法務部備查，並以適當方式公開，由相關權責機關回應處理之", "監獄得依媒體之請求，同意其進入適當處所採訪或參觀；並得依民眾之請求，同意其進入適當處所 參觀"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00261', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，有關受刑人入監的敘述，下列敘述何者錯誤？', '["受刑人入監時，指揮執行之檢察署應將指揮書附具裁判書及其他應備文件，以書面、電子傳輸或其 他適當方式送交監獄", "受刑人入監時，無指揮書者，仍應收監，但通知檢察署補正", "對於新入監者，應就其個性、身心狀況、經歷、教育程度及其他相關事項，加以調查", "於少年受刑人入少年矯正學校或監獄時，其應備文件除指揮書附具裁判書及其他應備文件外，尚應 包括其犯罪原因、動機、境遇、學歷、經歷、身心狀況及可供處遇之參考事項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00262', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["為保護受刑人個人資料之安全，監獄不得蒐集、調查與受刑人有關之資料", "為達到矯治處遇之目的，監獄應調查與受刑人有關之資料", "為調查與受刑人有關之資料，以達到矯治處遇之目的，得無限制地蒐集、處理或利用受刑人之個人 資料", "為調查與受刑人有關之資料，以達到矯治處遇之目的，得請求機關（構）、法人、團體或個人提供 相關資料，機關（構）、法人、團體或個人即使有正當理由，亦不得拒絕"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00263', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["對於新入監者，應就其個性、身心狀況、經歷、教育程度及其他相關事項，加以調查。但以判決書 所載之範圍為之", "入監之新收調查期間，不得逾一個月", "監獄應於受刑人入監後六個月內，依其入監調查所得之資料，訂定其個別處遇計畫，並適時修正", "入監之新收調查期間，不得逾二個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00264', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["殘餘刑期在三個月以下之入監或在監婦女請求攜帶未滿三歲之子女，監獄得准許之", "殘餘刑期逾一個月之入監或在監婦女請求攜帶未滿三歲之子女，經監獄檢具相關資料通知子女戶 籍所在地直轄市、縣（市）社會福利主管機關評估認符合子女最佳利益者，監獄得准許之", "子女隨母入監最多至滿五歲為止。但經社會福利主管機關評估，認在監符合子女最佳利益者，最 多得延長在監安置期間至子女滿五歲六個月為止", "為照顧安置在監子女，監獄應規劃活動空間及提供必要之設施或設備，並得洽請社會福利及相關機 關（構）、法人、團體或個人協助受刑人育兒相關教育與指導"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00265', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["為維護監獄秩序及安全，防止違禁物品流入，受刑人入監時，應檢查其身體、衣類及攜帶之物品， 但不得採集其尿液檢驗", "受刑人入監時，應檢查身體，縱須脫衣檢查，亦得於大庭廣眾下為之", "非有事實足認受刑人有夾藏違禁物品或有其他危害監獄秩序及安全之虞，不得為侵入性檢查", "受刑人入監時，為辨識受刑人身分，應對其照相或記錄其他身體特徵，但不得採取其指紋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00266', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄辦理文康活動，依監獄行刑法第45條得使用視聽器材輔助，有關此一特殊教化方式之敘述，下 列何者錯誤？', '["為教化之輔助", "為學習之工具", "為娛樂之手段", "為戒管之準備"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
